simple_types.code:
type Button_Clicks is range 0 .. 255 with
  Convention => C,
  Size       => 8;

type Button_Masks is mod 2 ** 32 with
  Convention => C,
  Size       => 32;

type IDs is range 0 .. 2 ** 32 - 1 with
  Convention => C,
  Size       => 32;

type Movement_Values is range -2 ** 31 .. 2 ** 31 - 1 with
  Convention => C,
  Size       => 32;

type Wheel_Values is range -2 ** 31 .. 2 ** 31 - 1 with
  Convention => C,
  Size       => 32;

record_types.code:
type Button_Events is
   record
      Event_Type : Event_Types;
      Time_Stamp : Time_Stamps;
      Window     : SDL.Video.Windows.ID;
      Which      : IDs;
      Button     : Buttons;
      State      : Button_State;
      Clicks     : Button_Clicks;
      Padding_1  : Padding_8;
      X          : SDL.Natural_Coordinate;
      Y          : SDL.Natural_Coordinate;
   end record;

type Motion_Events is
   record
      Event_Type : Event_Types;
      Time_Stamp : Time_Stamps;
      Window     : SDL.Video.Windows.ID;
      Which      : IDs;
      Mask       : Button_Masks;
      X          : SDL.Natural_Coordinate;
      Y          : SDL.Natural_Coordinate;
      X_Relative : Movement_Values;
      Y_Relative : Movement_Values;
   end record;

type Wheel_Events is
   record
      Event_Type : Event_Types;
      Time_Stamp : Time_Stamps;
      Window     : SDL.Video.Windows.ID;
      Which      : IDs;
      X          : Wheel_Values;
      Y          : Wheel_Values;
      Direction  : Wheel_Directions;
   end record;
